31	func (r *Reconciler) createOrApplyDeployments(istiocsr *v1alpha1.IstioCSR, resourceLabels map[string]string, istioCSRCreateRecon bool) error {
32		desired, err := r.getDeploymentObject(istiocsr, resourceLabels)
33		if err != nil {
34			return fmt.Errorf("failed to generate deployment resource for creation in %s: %w", istiocsr.GetNamespace(), err)
35		}
36	
37		deploymentName := fmt.Sprintf("%s/%s", desired.GetNamespace(), desired.GetName())
38		r.log.V(4).Info("reconciling deployment resource", "name", deploymentName)
39		fetched := &appsv1.Deployment{}
40		exist, err := r.Exists(r.ctx, client.ObjectKeyFromObject(desired), fetched)
41		if err != nil {
42			return common.FromClientError(err, "failed to check %s deployment resource already exists", deploymentName)
43		}
44	
45		if exist {
46			if istioCSRCreateRecon {
47				r.eventRecorder.Eventf(istiocsr, corev1.EventTypeWarning, "ResourceAlreadyExists", "%s deployment resource already exists, maybe from previous installation", deploymentName)
48			}
49			if hasObjectChanged(desired, fetched) {
50				r.log.V(1).Info("deployment has been modified, updating to desired state", "name", deploymentName)
51				if err := r.UpdateWithRetry(r.ctx, desired); err != nil {
52					return common.FromClientError(err, "failed to update %s deployment resource", deploymentName)
53				}
54				r.eventRecorder.Eventf(istiocsr, corev1.EventTypeNormal, "Reconciled", "deployment resource %s reconciled back to desired state", deploymentName)
55			} else {
56				r.log.V(4).Info("deployment resource already exists and is in expected state", "name", deploymentName)
57			}
58		}
59	
60		if !exist {
61			if err := r.Create(r.ctx, desired); err != nil {
62				return common.FromClientError(err, "failed to create %s deployment resource", deploymentName)
63			}
64			r.eventRecorder.Eventf(istiocsr, corev1.EventTypeNormal, "Reconciled", "deployment resource %s created", deploymentName)
65		}
66	
67		if err := r.updateImageInStatus(istiocsr, desired); err != nil {
68			return common.FromClientError(err, "failed to update %s/%s istiocsr status with image info", istiocsr.GetNamespace(), istiocsr.GetName())
69		}
70		return nil
71	}
