73	func (r *Reconciler) getDeploymentObject(istiocsr *v1alpha1.IstioCSR, resourceLabels map[string]string) (*appsv1.Deployment, error) {
74		if err := r.assertIssuerRefExists(istiocsr); err != nil {
75			return nil, fmt.Errorf("failed to verify issuer in %s/%s: %w", istiocsr.GetNamespace(), istiocsr.GetName(), err)
76		}
77	
78		deployment := decodeDeploymentObjBytes(assets.MustAsset(deploymentAssetName))
79	
80		common.UpdateNamespace(deployment, istiocsr.GetNamespace())
81		common.UpdateResourceLabels(deployment, resourceLabels)
82		updatePodTemplateLabels(deployment, resourceLabels)
83	
84		updateArgList(deployment, istiocsr)
85	
86		if err := updateResourceRequirement(deployment, istiocsr); err != nil {
87			return nil, fmt.Errorf("failed to update resource requirements: %w", err)
88		}
89		if err := updateAffinityRules(deployment, istiocsr); err != nil {
90			return nil, fmt.Errorf("failed to update affinity rules: %w", err)
91		}
92		if err := updatePodTolerations(deployment, istiocsr); err != nil {
93			return nil, fmt.Errorf("failed to update pod tolerations: %w", err)
94		}
95		if err := updateNodeSelector(deployment, istiocsr); err != nil {
96			return nil, fmt.Errorf("failed to update node selector: %w", err)
97		}
98		if err := r.updateImage(deployment); err != nil {
99			return nil, common.NewIrrecoverableError(err, "failed to update image %s/%s", istiocsr.GetNamespace(), istiocsr.GetName())
100		}
101		if err := r.updateVolumes(deployment, istiocsr, resourceLabels); err != nil {
102			return nil, fmt.Errorf("failed to update volume %s/%s: %w", istiocsr.GetNamespace(), istiocsr.GetName(), err)
103		}
104	
105		return deployment, nil
106	}
