278	func (r *Reconciler) updateVolumes(deployment *appsv1.Deployment, istiocsr *v1alpha1.IstioCSR, resourceLabels map[string]string) error {
279		// Use user-configured CA certificate if provided
280		if istiocsr.Spec.IstioCSRConfig.CertManager.IstioCACertificate != nil {
281			if err := r.handleUserProvidedCA(deployment, istiocsr, resourceLabels); err != nil {
282				return common.FromError(err, "failed to validate and mount CA certificate ConfigMap")
283			}
284			return nil
285		}
286	
287		// Fall back to issuer-based CA certificate if CA certificate is not configured
288		// Handle issuer-based CA configuration
289		if err := r.handleIssuerBasedCA(deployment, istiocsr, resourceLabels); err != nil {
290			return err
291		}
292	
293		return nil
294	}
295	
296	// handleUserProvidedCA processes user-provided CA certificate configuration.
297	//
298	// It performs the following operations:
299	//  1. Validates that the source ConfigMap exists
300	//  2. Adds a watch label to the source ConfigMap for change tracking
301	//  3. Validates that the ConfigMap contains the specified key and is a valid CA certificate
302	//  4. Creates or updates a copy of the ConfigMap in the IstioCSR namespace
303	//  5. Configures the deployment to mount the CA certificate volume
304	//
305	// The caller must ensure that `istiocsr.Spec.IstioCSRConfig.CertManager.IstioCACertificate`
306	// is not nil before calling this function to avoid a panic.
307	//
308	// Returns an error if any validation fails or if ConfigMap operations fail.
309	func (r *Reconciler) handleUserProvidedCA(deployment *appsv1.Deployment, istiocsr *v1alpha1.IstioCSR, resourceLabels map[string]string) error {
310		caCertConfig := istiocsr.Spec.IstioCSRConfig.CertManager.IstioCACertificate
311	
312		// Determine the namespace - use specified namespace or default to IstioCSR namespace
313		namespace := caCertConfig.Namespace
314		if namespace == "" {
315			namespace = istiocsr.GetNamespace()
316		}
317	
318		// Validate that the source ConfigMap exists
319		sourceConfigMapKey := types.NamespacedName{
320			Name:      caCertConfig.Name,
321			Namespace: namespace,
322		}
323	
324		sourceConfigMap := &corev1.ConfigMap{}
325		if err := r.Get(r.ctx, sourceConfigMapKey, sourceConfigMap); err != nil {
326			return common.NewIrrecoverableError(err, "failed to fetch CA certificate ConfigMap %s/%s", sourceConfigMapKey.Namespace, sourceConfigMapKey.Name)
327		}
328	
329		// Add watch label to the source ConfigMap to trigger reconciliation on changes.
330		// This is done before validation so that if validation fails now, fixing the ConfigMap
331		// will trigger reconciliation.
332		if err := r.updateWatchLabel(sourceConfigMap, istiocsr); err != nil {
333			return common.FromClientError(err, "failed to update watch label on CA certificate ConfigMap %s/%s", sourceConfigMapKey.Namespace, sourceConfigMapKey.Name)
334		}
335	
336		// Validate that the specified key exists in the ConfigMap
337		if _, exists := sourceConfigMap.Data[caCertConfig.Key]; !exists {
338			return common.NewIrrecoverableError(fmt.Errorf("key %q not found in ConfigMap %s/%s", caCertConfig.Key, sourceConfigMapKey.Namespace, sourceConfigMapKey.Name), "invalid CA certificate ConfigMap %s/%s", sourceConfigMapKey.Namespace, sourceConfigMapKey.Name)
339		}
340	
341		// Validate that the key contains PEM-formatted content
342		pemData := sourceConfigMap.Data[caCertConfig.Key]
343		if err := r.validatePEMData(pemData); err != nil {
344			return common.NewIrrecoverableError(err, "invalid PEM data in CA certificate ConfigMap %s/%s key %q", sourceConfigMapKey.Namespace, sourceConfigMapKey.Name, caCertConfig.Key)
345		}
346	
347		// Create a managed copy of the ConfigMap in the IstioCSR namespace.
348		// The operator does not directly mount the user-provided ConfigMap but creates a managed copy
349		// (cert-manager-istio-csr-issuer-ca-copy) in the IstioCSR namespace. This approach enables the
350		// operator to validate any changes to the source ConfigMap before propagating them to the istio-csr
351		// agent, as ConfigMap changes automatically propagate to mounted pods. The watch label on the source
352		// ConfigMap triggers reconciliation when modified, allowing the operator to re-validate and update
353		// its managed copy. Additionally, if a user directly modifies the operator-managed copy, it will be
354		// reconciled back to the desired state derived from the validated source ConfigMap.
355		if err := r.createOrUpdateCAConfigMap(istiocsr, pemData, resourceLabels); err != nil {
356			return common.FromClientError(err, "failed to create CA certificate ConfigMap copy")
357		}
358	
359		// Mount the copied CA certificate ConfigMap (always uses the standard name)
360		updateVolumeWithIssuerCA(deployment)
361	
362		return nil
363	}
364	
365	// handleIssuerBasedCA handles the creation of CA ConfigMap from issuer secret and volume mounting.
366	func (r *Reconciler) handleIssuerBasedCA(deployment *appsv1.Deployment, istiocsr *v1alpha1.IstioCSR, resourceLabels map[string]string) error {
367		var (
368			issuerConfig certmanagerv1.IssuerConfig
369		)
370	
371		obj, err := r.getIssuer(istiocsr)
372		if err != nil {
373			return common.FromClientError(err, "failed to fetch issuer")
374		}
375	
376		issuerRefKind := strings.ToLower(istiocsr.Spec.IstioCSRConfig.CertManager.IssuerRef.Kind)
377		switch issuerRefKind {
378		case clusterIssuerKind:
379			clusterIssuer, ok := obj.(*certmanagerv1.ClusterIssuer)
380			if !ok {
381				return common.FromClientError(fmt.Errorf("failed to convert to ClusterIssuer"), "failed to fetch issuer")
382			}
383			issuerConfig = clusterIssuer.Spec.IssuerConfig
384		case issuerKind:
385			issuer, ok := obj.(*certmanagerv1.Issuer)
386			if !ok {
387				return common.FromClientError(fmt.Errorf("failed to convert to Issuer"), "failed to fetch issuer")
388			}
389			issuerConfig = issuer.Spec.IssuerConfig
390		}
391	
392		shouldUpdateVolume := false
393	
394		if issuerConfig.CA != nil && issuerConfig.CA.SecretName != "" {
395			if err := r.createCAConfigMapFromIssuerSecret(istiocsr, issuerConfig, resourceLabels); err != nil {
396				return common.FromClientError(err, "failed to create CA ConfigMap")
397			}
398			shouldUpdateVolume = true
399		}
400	
401		if issuerConfig.CA == nil {
402			if err := r.createCAConfigMapFromIstiodCertificate(istiocsr, resourceLabels); err != nil {
403				return common.FromClientError(err, "failed to create CA ConfigMap")
404			}
405			shouldUpdateVolume = true
406		}
407	
408		if shouldUpdateVolume {
409			updateVolumeWithIssuerCA(deployment)
410		}
411	
412		return nil
413	}
414	
415	func updateVolumeWithIssuerCA(deployment *appsv1.Deployment) {
416		const (
417			caVolumeName = "root-ca"
418		)
419		var (
420			defaultMode = int32(420)
421		)
422	
423		desiredVolumeMount := corev1.VolumeMount{
424			Name:      caVolumeName,
425			MountPath: caVolumeMountPath,
426			ReadOnly:  true,
427		}
428	
429		desiredVolume := corev1.Volume{
430			Name: caVolumeName,
431			VolumeSource: corev1.VolumeSource{
432				ConfigMap: &corev1.ConfigMapVolumeSource{
433					LocalObjectReference: corev1.LocalObjectReference{
434						Name: IstiocsrCAConfigMapName,
435					},
436					Items: []corev1.KeyToPath{
437						{
438							Key:  IstiocsrCAKeyName,
439							Path: IstiocsrCAKeyName,
440							Mode: &defaultMode,
441						},
442					},
443					DefaultMode: &defaultMode,
444				},
445			},
446		}
447	
448		// Update or append volume mount in the istio-csr container
449		for i, container := range deployment.Spec.Template.Spec.Containers {
450			if container.Name == istiocsrContainerName {
451				volumeMountExists := false
452				for j, vm := range container.VolumeMounts {
453					if vm.Name == caVolumeName {
454						deployment.Spec.Template.Spec.Containers[i].VolumeMounts[j] = desiredVolumeMount
455						volumeMountExists = true
456						break
457					}
458				}
459				if !volumeMountExists {
460					deployment.Spec.Template.Spec.Containers[i].VolumeMounts = append(
461						deployment.Spec.Template.Spec.Containers[i].VolumeMounts,
462						desiredVolumeMount,
463					)
464				}
465				break
466			}
467		}
468	
469		// Update or append volume in the deployment
470		volumeExists := false
471		for i, vol := range deployment.Spec.Template.Spec.Volumes {
472			if vol.Name == caVolumeName {
473				deployment.Spec.Template.Spec.Volumes[i] = desiredVolume
474				volumeExists = true
475				break
476			}
477		}
478		if !volumeExists {
479			deployment.Spec.Template.Spec.Volumes = append(
480				deployment.Spec.Template.Spec.Volumes,
481				desiredVolume,
482			)
483		}
484	}
