550	// createOrUpdateCAConfigMap creates or updates the CA ConfigMap with the provided certificate data.
551	func (r *Reconciler) createOrUpdateCAConfigMap(istiocsr *v1alpha1.IstioCSR, certData string, resourceLabels map[string]string) error {
552		if certData == "" {
553			return fmt.Errorf("failed to find CA certificate")
554		}
555	
556		configmapKey := client.ObjectKey{
557			Name:      IstiocsrCAConfigMapName,
558			Namespace: istiocsr.GetNamespace(),
559		}
560		fetched := &corev1.ConfigMap{}
561		exist, err := r.Exists(r.ctx, configmapKey, fetched)
562		if err != nil {
563			return fmt.Errorf("failed to check if CA configmap exists: %w", err)
564		}
565	
566		desired := &corev1.ConfigMap{
567			ObjectMeta: metav1.ObjectMeta{
568				Name:      configmapKey.Name,
569				Namespace: configmapKey.Namespace,
570				Labels:    resourceLabels,
571			},
572			Data: map[string]string{
573				IstiocsrCAKeyName: certData,
574			},
575		}
576	
577		if exist && hasObjectChanged(desired, fetched) {
578			r.log.V(1).Info("ca configmap need update", "name", configmapKey)
579			if err := r.UpdateWithRetry(r.ctx, desired); err != nil {
580				return fmt.Errorf("failed to update %s configmap resource: %w", configmapKey, err)
581			}
582			r.eventRecorder.Eventf(istiocsr, corev1.EventTypeNormal, "Reconciled", "configmap resource %s reconciled back to desired state", configmapKey)
583		} else {
584			r.log.V(4).Info("configmap resource already exists and is in expected state", "name", configmapKey)
585		}
586	
587		if !exist {
588			if err := r.Create(r.ctx, desired); err != nil {
589				return fmt.Errorf("failed to create %s configmap resource: %w", configmapKey, err)
590			}
591			r.eventRecorder.Eventf(istiocsr, corev1.EventTypeNormal, "Reconciled", "configmap resource %s created", configmapKey)
592		}
593	
594		return nil
595	}
