633	// updateWatchLabel adds a watch label to any Kubernetes object that supports labels.
634	func (r *Reconciler) updateWatchLabel(obj client.Object, istiocsr *v1alpha1.IstioCSR) error {
635		labels := obj.GetLabels()
636		if labels == nil {
637			labels = make(map[string]string)
638		}
639		labels[IstiocsrResourceWatchLabelName] = fmt.Sprintf(istiocsrResourceWatchLabelValueFmt, istiocsr.GetNamespace(), istiocsr.GetName())
640		obj.SetLabels(labels)
641	
642		if err := r.UpdateWithRetry(r.ctx, obj); err != nil {
643			return fmt.Errorf("failed to update %s resource with watch label: %w", obj.GetName(), err)
644		}
645		return nil
646	}
